import React, { useState, useEffect } from 'react';
import { Search as SearchIcon } from 'lucide-react';
import TrackList from '../components/TrackList';
import { searchTracks, getAllTracks } from '../utils/api';
import { getGenreStyle } from '../utils/helpers';

const GENRES = [
  { id: 'blues', label: 'Blues' },
  { id: 'classical', label: 'Classical' },
  { id: 'country', label: 'Country' },
  { id: 'disco', label: 'Disco' },
  { id: 'hiphop', label: 'Hip-Hop' },
  { id: 'jazz', label: 'Jazz' },
  { id: 'metal', label: 'Metal' },
  { id: 'pop', label: 'Pop' },
  { id: 'reggae', label: 'Reggae' },
  { id: 'rock', label: 'Rock' },
];

export default function Search({ playTrack, toggleLike, isLiked, currentTrack, isPlaying }) {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState(null);
  const [genreTracks, setGenreTracks] = useState(null);
  const [selectedGenre, setSelectedGenre] = useState(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const timer = setTimeout(() => {
      if (query.trim().length >= 2) {
        setLoading(true);
        searchTracks(query).then(d => {
          setResults(d.tracks || []);
          setGenreTracks(null);
          setSelectedGenre(null);
        }).finally(() => setLoading(false));
      } else if (!query.trim()) {
        setResults(null);
      }
    }, 400);
    return () => clearTimeout(timer);
  }, [query]);

  const handleGenre = (genre) => {
    setSelectedGenre(genre);
    setQuery('');
    setResults(null);
    setLoading(true);
    getAllTracks(genre).then(d => setGenreTracks(d.tracks || [])).finally(() => setLoading(false));
  };

  const displayTracks = results || genreTracks;

  return (
    <div className="search-page">
      <div className="topbar" style={{ padding: '24px 0 0 0', position: 'static', marginBottom: 24 }}>
        <h1 style={{ fontSize: 28, fontWeight: 900 }}>Search</h1>
      </div>

      <div className="search-input-wrap">
        <SearchIcon size={20} className="search-input-icon" />
        <input
          className="search-input"
          placeholder="What do you want to listen to?"
          value={query}
          onChange={e => setQuery(e.target.value)}
          autoFocus
        />
      </div>

      {!query && !selectedGenre && (
        <>
          <h2 style={{ fontSize: 20, fontWeight: 700, marginBottom: 16 }}>Browse by Genre</h2>
          <div className="genre-grid">
            {GENRES.map(({ id, label }) => {
              const style = getGenreStyle(id);
              return (
                <div
                  key={id}
                  className="genre-card"
                  style={{ background: `linear-gradient(135deg, ${style.c1}, ${style.c2})` }}
                  onClick={() => handleGenre(id)}
                >
                  <h3>{label}</h3>
                  <span className="genre-emoji">{style.emoji}</span>
                </div>
              );
            })}
          </div>
        </>
      )}

      {loading && (
        <div className="loading-wrap">
          <div className="spinner" />
        </div>
      )}

      {displayTracks && !loading && (
        <>
          <div className="section-title" style={{ marginBottom: 16 }}>
            <span>{selectedGenre ? `${selectedGenre.charAt(0).toUpperCase() + selectedGenre.slice(1)} Tracks` : `Results for "${query}"`}</span>
            {selectedGenre && <a onClick={() => { setSelectedGenre(null); setGenreTracks(null); }}>← Back</a>}
          </div>
          {displayTracks.length === 0 ? (
            <div className="empty-state">
              <div style={{ fontSize: 48, marginBottom: 12 }}>🔍</div>
              <h2>No results found</h2>
              <p>Try a different search term</p>
            </div>
          ) : (
            <TrackList
              tracks={displayTracks}
              playTrack={playTrack}
              toggleLike={toggleLike}
              isLiked={isLiked}
              currentTrack={currentTrack}
              isPlaying={isPlaying}
            />
          )}
        </>
      )}
    </div>
  );
}
